-- Mini Z and Me, Water Play Activities (Ages 0–5)
-- Run in: Supabase Dashboard → SQL Editor

INSERT INTO activities (age, title, emoji, color, area, subject, duration, materials, steps, prior_stage, prior_desc, safety, ease_of_prep, is_custom) VALUES

-- AGE 0
(0,'Sponge Squeeze Bath','🧽','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Soft sponges','Warm water in a shallow tub','Towel'],ARRAY['Fill a shallow tub with a small amount of warm water.','Squeeze a wet sponge and let water drip onto baby''s tummy.','Describe the sensation: warm, wet, squeeze.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Always supervise near water.',9,false),
(0,'Water Sound Shakers','🫧','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Sealed plastic bottles','Coloured water (food colouring)','Strong waterproof tape'],ARRAY['Half-fill bottles with water and a drop of food colouring.','Seal tightly with tape.','Shake and hold up for baby to watch the swirling colour.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Ensure bottles are sealed completely before play.',8,false),
(0,'Wet Cloth Sensory','🧻','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Small cloths or flannels','Cool water','Warm water'],ARRAY['Dampen cloths in cool and warm water.','Gently lay each cloth on baby''s arm or tummy in turn.','Name each sensation: cool, warm, soft.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.',NULL,9,false),
(0,'Ice Cube Touch','🧊','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Small ice cubes','Muslin cloth','Towel'],ARRAY['Wrap an ice cube in a piece of muslin cloth.','Gently touch it to baby''s palm and fingers.','Describe: cold, wet, melting.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Do not place unwrapped ice directly on baby''s skin for long.',9,false),
(0,'Drip Drop','💧','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Small jug of water','Towel to catch drips','Shallow tray'],ARRAY['Sit baby on your lap with a towel underneath.','Raise the jug and slowly drip water from a height onto baby''s open palm.','Describe: drip, drop, water.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Always supervise near water.',9,false),
(0,'Float and Sink Basket','🛁','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Shallow tub of water','Mix of floating and sinking objects','Towel'],ARRAY['Fill a shallow tub with a small amount of water.','Place objects in one at a time.','Point and narrate: look, it floats! That one sinks!'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Use objects larger than baby''s fist. Always supervise.',8,false),
(0,'Bubble Wrap Water Mat','💦','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Large zip-lock bag','Water','Glitter or sequins','Strong tape'],ARRAY['Fill a large zip bag with water and a pinch of glitter.','Seal firmly and tape all edges.','Place flat on the floor for tummy time and let baby press the water.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Tape all edges securely. Supervise at all times.',7,false),
(0,'Rain Bottle','🌧️','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Plastic bottle with lid','Pin or nail to make holes','Water'],ARRAY['Poke small holes in the bottle lid.','Fill the bottle with water and screw the lid on.','Tip upside down and shake gently over baby''s feet.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Always supervise near water.',7,false),
(0,'Colour Water Watch','🌈','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Clear glass or jar','Water','Food colouring'],ARRAY['Fill a clear jar with water and place at baby''s eye level.','Drop in a small amount of food colouring.','Let baby watch the colour bloom and spread through the water.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.',NULL,9,false),
(0,'Wet Sand Footprint Tray','👣','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Shallow tray','Damp sand and water mix','Towel'],ARRAY['Mix sand and water in a shallow tray to a soft consistency.','Gently press baby''s feet into the sand.','Lift away to reveal the footprint.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Wash feet after. Supervise so sand is not mouthed.',7,false),
(0,'Mirror Splash','🪞','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Unbreakable mirror','Shallow water in a tray','Towel'],ARRAY['Place an unbreakable mirror in a tray with a thin layer of water.','Hold baby over it so they can see their reflection.','Let them pat the water and watch the reflection ripple.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Use an unbreakable mirror only. Always supervise.',7,false),
(0,'Herb Water','🌿','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Warm water in a tray','Fresh lavender or mint sprigs','Towel'],ARRAY['Float fresh herb sprigs in a tray of warm water.','Hold baby over the tray to smell the herbs.','Gently guide baby''s hand to touch the floating sprigs.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Always supervise near water.',8,false),
(0,'Foam Mountain','☁️','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Shaving foam or gentle whipped soap','Shallow tray','Towel'],ARRAY['Squirt shaving foam into a shallow tray.','Shape it into a soft mound.','Let baby pat and squish the foam with both hands.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Use fragrance-free foam. Keep away from eyes and mouth.',9,false),
(0,'Ice Painting','🎨','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Coloured ice blocks (water and food colouring frozen)','Black paper','Tray to catch drips'],ARRAY['Freeze coloured water in ice cube trays or small cups.','Place black paper in a tray.','Let baby hold or guide the ice block across the paper and watch the colour trail appear.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Do not let baby mouth the ice. Supervise closely.',6,false),
(0,'Water Xylophone','🎵','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['5 glasses or jars','Water at different levels','Metal spoon'],ARRAY['Fill glasses with different amounts of water.','Tap each glass with a spoon to demonstrate the tones.','Help baby reach out and tap a glass.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Keep glass out of baby''s reach when not actively playing.',7,false),
(0,'Bubble Wand Watching','🫧','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Bubble wand','Bubble solution','Open space'],ARRAY['Blow gentle bubbles at baby''s eye level.','Let baby track the bubbles with their eyes.','Help them reach or bat at a floating bubble.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.',NULL,9,false),
(0,'Warm vs Cool Water','♨️','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Two bowls of water (one warm, one cool)','Towel'],ARRAY['Fill two bowls, one warm, one cool.','Dip baby''s hand in the warm bowl, then the cool.','Name each: warm, cool, and watch their reaction.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Test warm water on your wrist first, it should feel comfortable, not hot.',9,false),
(0,'Floating Flower Petals','🌸','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Fresh flower petals','Shallow tray of water','Towel'],ARRAY['Float colourful petals on the surface of a shallow tray of water.','Hold baby close so they can reach for a petal.','Name the colours and textures: pink, soft, smooth.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Always supervise near water.',8,false),
(0,'Waterfall from Height','💧','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Jug of water','Large tub or bowl','Towel'],ARRAY['Position a large tub on the floor.','Lift a jug and pour water into the tub from a height.','Let baby watch the water stream fall and splash.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Always supervise near water.',9,false),
(0,'Soapy Cloud Water','☁️','#4dc3ff','Water Play · Sensory','Water Play','5–15 min',ARRAY['Dish soap','Water in a bowl','Hand mixer or whisk'],ARRAY['Add a small amount of dish soap to a bowl of water.','Whip into a thick foam using a hand mixer or whisk.','Let baby pat and explore the fluffy foam.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Keep foam away from baby''s eyes. Use gentle, baby-safe soap.',8,false),

-- AGE 1
(1,'Waterfall Wall','💦','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Zip-lock bags','Water','Strong tape'],ARRAY['Fill zip-lock bags with water and tape to a wall at child''s height.','Poke small holes in the bags to let water drip out.','Let child touch the drips and watch the water flow down.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Always supervise near water.',7,false),
(1,'Colour Mixing Bottles','🌈','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Clear sealed bottles','Water in two primary colours','Strong tape'],ARRAY['Half-fill two sealed bottles with different coloured water.','Show shaking to mix the colours together.','Ask: what colour do you think it will make?'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Ensure bottles are sealed completely before play.',8,false),
(1,'Car Wash','🚗','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Toy cars','Tub of soapy water','Sponge and small brush'],ARRAY['Fill a tub with warm soapy water.','Show how to dip the car in and scrub it clean.','Let child wash and rinse their own toy cars.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Always supervise near water.',9,false),
(1,'Fishing for Pompoms','🎣','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Shallow tub of water','Coloured pompoms','Ladle or slotted spoon'],ARRAY['Float coloured pompoms in a shallow tub of water.','Show how to scoop them out with a ladle.','Count how many of each colour have been caught.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Always supervise near water.',9,false),
(1,'Baby Car Wash','🚿','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Bowls of warm soapy water','Sponges and soft brushes','Toy vehicles'],ARRAY['Set up bowls of soapy water on the ground.','Show how to dip and scrub each vehicle.','Let child work through washing each toy independently.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Always supervise near water.',9,false),
(1,'Ice Excavation','🧊','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Small toys frozen in a large block of ice','Warm water','Small tools or spoons'],ARRAY['Freeze small toys in a large container of water overnight.','Give child warm water and tools to melt and chip the ice.','Celebrate each toy discovered inside.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Supervise use of tools. Ensure no sharp edges on the ice.',6,false),
(1,'Muddy Puddle Stomp','👢','#4dc3ff','Water Play · Outdoor','Water Play','10–20 min',ARRAY['Wellies or waterproof boots','A puddle or shallow tray of muddy water','Old clothes'],ARRAY['Put on wellies and old clothes.','Find a puddle or create one with a tray of muddy water.','Jump in with both feet, bigger splash is better!'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Ensure area is safe with no hidden hazards underfoot.',9,false),
(1,'Watering the Garden','🌱','#4dc3ff','Water Play · Outdoor','Water Play','10–20 min',ARRAY['Small watering can','Real or fake plants to water','Outdoor space'],ARRAY['Fill the watering can with water together.','Show how to tilt the can to water a plant.','Let child water each plant in turn.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.',NULL,9,false),
(1,'Pouring Station','🫗','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Jugs and containers of different sizes','Water','Towel or outdoor space'],ARRAY['Line up jugs and containers.','Demonstrate pouring water from one container to another.','Let child explore filling and pouring freely.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Always supervise near water.',9,false),
(1,'Foam Beard','😄','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Shaving foam','Large mirror','Towel'],ARRAY['Apply shaving foam to the mirror at child''s height.','Show how to draw a beard or face with a finger.','Let child create their own foam face design.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Use fragrance-free foam. Keep away from eyes.',9,false),
(1,'Splashing Stones','🪨','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Pebbles or small stones','Large bucket of water','Old clothes'],ARRAY['Fill a bucket with water.','Drop pebbles in one at a time and watch the splash.','Try dropping from different heights and observe the difference.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Always supervise near water. Use smooth stones only.',9,false),
(1,'Rain Painting','🌧️','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Thick paper','Washable paint','Light rain'],ARRAY['Paint shapes or dots on the paper with washable paint.','Place the paper outside in light rain.','Watch the raindrops blend and move the colours.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.',NULL,7,false),
(1,'Bottle Boat','⛵','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Sealed plastic bottles','Paddling pool or large tub of water','Small toy passengers'],ARRAY['Seal bottles tightly and place them in water.','Show how to push and float the bottle boats.','Add small toy passengers inside transparent bottles.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Always supervise near water.',8,false),
(1,'Washing Dollies','🧸','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Toy dolls','Warm soapy water in a bowl','Small flannel'],ARRAY['Fill a bowl with warm soapy water.','Show how to wash the doll''s face and hair gently.','Let child bath and dry the doll independently.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Always supervise near water.',9,false),
(1,'Snow in Summer','❄️','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Ice shavings or crushed ice','Shallow tray','Waterproof play space'],ARRAY['Place a large amount of ice shavings in a shallow tray.','Let child touch, scoop and explore the icy texture.','Watch and talk about what happens as the ice melts.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Ensure hands don''t get too cold. Have a warm towel ready.',7,false),
(1,'Paint in a Bag','🎨','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Zip-lock bag','Washable paint (two colours)','Strong tape'],ARRAY['Squeeze two colours of paint into a zip bag and seal tightly.','Tape the bag to a table or window.','Let child squish and mix the colours through the bag.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Ensure bag is fully sealed. Supervise at all times.',9,false),
(1,'Bubble Stomp','🫧','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Bubble wand and bubble solution','Open space'],ARRAY['Blow bubbles low to the ground.','Encourage child to stomp on each bubble as it lands.','Count how many bubbles they pop in a row.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.',NULL,9,false),
(1,'Watercolour on Wet Paper','🖌️','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Thick paper','Watercolour paints','Clean water and sponge'],ARRAY['Wet the paper all over with a sponge or brush.','Drop watercolour paint onto the wet surface.','Watch the colours bloom, bleed and blend together.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.',NULL,8,false),
(1,'Sink or Float Sorting','⚖️','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Tub of water','Mix of objects (sinking and floating)','Two labelled bowls'],ARRAY['Predict together: will it sink or float?','Drop each object in the water one at a time.','Sort into two bowls: sink or float.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Always supervise near water. Use objects too large to swallow.',8,false),
(1,'Frozen Herb Blocks','🌿','#4dc3ff','Water Play · Sensory','Water Play','10–20 min',ARRAY['Fresh herbs (mint, rosemary, lavender)','Water','Ice cube trays'],ARRAY['Place herbs into ice cube trays and cover with water.','Freeze overnight.','Let child hold and explore the ice cubes as they melt, smelling the herbs.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Ensure ice isn''t too cold for small hands.',6,false),

-- AGE 2
(2,'Flower Potions','🌸','#4dc3ff','Water Play · Sensory','Water Play','15–30 min',ARRAY['Flower petals','Water in small cups','Food colouring'],ARRAY['Collect petals and place them in cups of water.','Add food colouring and stir to make a potion.','Compare the colours and smells of each potion.'],'1 year, Wobbler','At one, they explored by grabbing and putting things in their mouth. Now they can use simple tools on purpose, which builds wrist and finger control.',NULL,9,false),
(2,'Mud Kitchen Soups','🥘','#4dc3ff','Water Play · Outdoor','Water Play','15–30 min',ARRAY['Old pots and spoons','Dirt and water','Sticks and leaves'],ARRAY['Set up an outdoor mud kitchen with old pots.','Add dirt, water, leaves and sticks to make soup.','Stir, pretend-taste and serve the mud soup.'],'1 year, Wobbler','At one, they explored by grabbing and putting things in their mouth. Now they can use simple tools on purpose, which builds wrist and finger control.','Ensure child does not eat the mud. Wash hands after.',9,false),
(2,'Colour Mixing Lab','🔬','#4dc3ff','Water Play · Science','Water Play','15–30 min',ARRAY['Ice cube trays','Primary coloured water','Pipettes or small spoons'],ARRAY['Fill ice cube trays with red, yellow and blue water.','Use a pipette to transfer colours into empty sections.','Watch the new colours appear and name them.'],'1 year, Wobbler','At one, they explored by grabbing and putting things in their mouth. Now they can use simple tools on purpose, which builds wrist and finger control.',NULL,7,false),
